# Category: race_condition

defmodule BankAccount do
  use GenServer

  @balance_table __MODULE__

  def start_link(_, state) do
    GenServer.start_link(__MODULE__, %{}, name: __MODULE__)
  end

  def init(state) do
    :ets.new(@balance_table, [:named_table, :set, temporary: true])
    :ets.insert(@balance_table, {self(), Map.new()})
    {:ok, state}
  end

  def get_balance(account) do
    GenServer.call(@balance_table, :lookup, account)
  end

  def validate_transaction({account, amount}) do
    balance = get_balance(account) |> Map.get(:data)
    if balance >= amount do
      {:ok, true}
    else
      {:error, "Insufficient funds"}
    end
  end

  def transaction({account, amount}) do
    {:ok, result} = validate_transaction(account, amount)
    if result == :ok do
      balance = get_balance(account)
      new_balance = Map.put(balance, :data, (balance[:data] - amount))

      :ets.insert(@balance_table, {self(), new_balance})
      {:ok, "Transaction successful"}
    else
      {:error, result}
    end
  end
end